import React, { useState, useEffect, useCallback, useRef } from 'react';
import api from '../api/api';
import Chart from 'chart.js/auto';
import {
    FaFire,
    FaWeight,
    FaHeartbeat,
    FaSpinner,
    FaChartLine,
} from 'react-icons/fa';

// Helper function (UNCHANGED)
const createChart = (ctx, type, data, options) => {
    if (ctx.chart) ctx.chart.destroy();
    ctx.chart = new Chart(ctx, { type, data, options });
};

const ProgressChart = ({ profile }) => {
    const [history, setHistory] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const calorieChartRef = useRef(null);
    const bodyChartRef = useRef(null);
    const riskChartRef = useRef(null);

    const fetchHistory = useCallback(async () => {
        setLoading(true);
        setError(null);
        try {
            const response = await api.get('/analytics/history');
            setHistory(response.data.data);
        } catch (err) {
            console.error('Analytics fetch error:', err);
            setError('Could not load historical data. Ensure backend service is running.');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchHistory();
    }, [fetchHistory]);

    /* ===================== CHART LOGIC (UNCHANGED) ===================== */
    useEffect(() => {
        if (!history) return;

        const timeline = history.timeline.map(date =>
            new Date(date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
        );

        const themeColors = {
            target: 'rgba(255,255,255,0.4)',
            intake: 'rgba(52,211,153,0.85)',
            protein: 'rgba(56,189,248,0.85)',
            carbs: 'rgba(251,191,36,0.85)',
            fats: 'rgba(248,113,133,0.85)',
            weight: 'rgba(20,184,166,0.9)',
            risk: 'rgba(129,140,248,0.9)',
        };

        const textDefault = '#CBD5E1';

        /* 1. Calories */
        if (calorieChartRef.current) {
            createChart(calorieChartRef.current, 'line', {
                labels: timeline,
                datasets: [
                    {
                        label: 'Calorie Target',
                        data: history.calorieData.target,
                        borderColor: themeColors.target,
                        borderDash: [5, 5],
                        pointRadius: 0,
                        yAxisID: 'y',
                    },
                    {
                        label: 'Actual Intake (kcal)',
                        data: history.calorieData.intake,
                        borderColor: themeColors.intake,
                        backgroundColor: themeColors.intake,
                        yAxisID: 'y',
                    },
                    {
                        label: 'Protein (g)',
                        data: history.calorieData.protein,
                        backgroundColor: themeColors.protein,
                        stack: 'macros',
                        yAxisID: 'y1',
                    },
                    {
                        label: 'Carbs (g)',
                        data: history.calorieData.carbs,
                        backgroundColor: themeColors.carbs,
                        stack: 'macros',
                        yAxisID: 'y1',
                    },
                    {
                        label: 'Fats (g)',
                        data: history.calorieData.fats,
                        backgroundColor: themeColors.fats,
                        stack: 'macros',
                        yAxisID: 'y1',
                    },
                ],
            }, {
                responsive: true,
                maintainAspectRatio: false,
                scales: {
                    x: { ticks: { color: textDefault } },
                    y: {
                        position: 'left',
                        ticks: { color: themeColors.intake },
                        title: { display: true, text: 'Calories (kcal)', color: themeColors.intake },
                    },
                    y1: {
                        position: 'right',
                        ticks: { color: themeColors.protein },
                        title: { display: true, text: 'Macros (g)', color: themeColors.protein },
                        grid: { drawOnChartArea: false },
                    },
                },
                plugins: { legend: { labels: { color: textDefault } } },
            });
        }

        /* 2. Body */
        if (bodyChartRef.current) {
            createChart(bodyChartRef.current, 'line', {
                labels: timeline,
                datasets: [
                    {
                        label: 'Weight (kg)',
                        data: history.bodyData.weight,
                        borderColor: themeColors.weight,
                        tension: 0.35,
                        yAxisID: 'y',
                    },
                    {
                        label: `BMI (${profile.height || 'N/A'} cm)`,
                        data: history.bodyData.bmi,
                        borderColor: themeColors.risk,
                        tension: 0.35,
                        yAxisID: 'y1',
                    },
                    {
                        label: 'Goal Weight',
                        data: Array(timeline.length).fill(history.bodyData.goalWeight),
                        borderColor: 'rgba(255,255,255,0.25)',
                        borderDash: [4, 4],
                        pointRadius: 0,
                        yAxisID: 'y',
                    },
                ],
            }, {
                responsive: true,
                maintainAspectRatio: false,
                scales: {
                    x: { ticks: { color: textDefault } },
                    y: {
                        ticks: { color: themeColors.weight },
                        title: { display: true, text: 'Weight (kg)', color: themeColors.weight },
                    },
                    y1: {
                        position: 'right',
                        ticks: { color: themeColors.risk },
                        title: { display: true, text: 'BMI', color: themeColors.risk },
                        grid: { drawOnChartArea: false },
                    },
                },
                plugins: { legend: { labels: { color: textDefault } } },
            });
        }

        /* 3. Risk */
        if (riskChartRef.current) {
            createChart(riskChartRef.current, 'line', {
                labels: timeline,
                datasets: [{
                    label: 'AI Risk Score (0–1)',
                    data: history.riskData.riskScore,
                    borderColor: themeColors.risk,
                    backgroundColor: 'rgba(129,140,248,0.25)',
                    fill: true,
                    tension: 0.4,
                    pointRadius: 4,
                }],
            }, {
                responsive: true,
                maintainAspectRatio: false,
                scales: {
                    y: {
                        min: 0,
                        max: 1,
                        ticks: { color: textDefault, stepSize: 0.2 },
                    },
                    x: { ticks: { color: textDefault } },
                },
                plugins: { legend: { labels: { color: textDefault } } },
            });
        }
    }, [history, profile]);

    /* ===================== UI STATES ===================== */
    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[300px] text-emerald-400">
                <FaSpinner className="animate-spin text-2xl mr-3" />
                <span className="text-lg font-semibold">Loading analytics...</span>
            </div>
        );
    }

    if (error || !history) {
        return (
            <div className="text-center py-16 text-red-400 font-semibold">
                {error || 'No sufficient historical data available.'}
            </div>
        );
    }

    /* ===================== MODERN UI ===================== */
    return (
        <div className="space-y-10">
            {/* Header */}
            <div className="flex items-center gap-4">
                <div className="p-3 rounded-xl bg-gradient-to-r from-indigo-500 to-emerald-400">
                    <FaChartLine className="text-white text-xl" />
                </div>
                <div>
                    <h2 className="text-3xl font-bold text-white">Health Analytics</h2>
                    <p className="text-slate-400 text-sm">
                        Visual insights into your nutrition, body metrics & AI health risk
                    </p>
                </div>
            </div>

            {/* Charts Grid */}
            <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                {/* Calories */}
                <div className="glass-card">
                    <h3 className="section-title text-emerald-400">
                        <FaFire /> Calorie & Macro Adherence
                    </h3>
                    <div className="chart-box">
                        <canvas ref={calorieChartRef} />
                    </div>
                </div>

                {/* Body */}
                <div className="glass-card">
                    <h3 className="section-title text-teal-400">
                        <FaWeight /> Weight & BMI Progress
                    </h3>
                    <div className="chart-box">
                        <canvas ref={bodyChartRef} />
                    </div>
                </div>
            </div>

            {/* Risk */}
            <div className="glass-card">
                <h3 className="section-title text-indigo-400">
                    <FaHeartbeat /> Predictive AI Risk Score
                </h3>
                <p className="text-sm text-slate-400 mb-4 max-w-3xl">
                    This score reflects predicted metabolic and lifestyle risk based on your
                    long-term trends. Lower values indicate better health stability.
                </p>
                <div className="chart-box">
                    <canvas ref={riskChartRef} />
                </div>
            </div>
        </div>
    );
};

export default ProgressChart;
